import{_ as n,o,c as t,ae as e,j as a}from"./chunks/framework.CyZiF_rV.js";const k=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"pl/limity/limity-api.md","filePath":"pl/limity/limity-api.md"}'),s={name:"pl/limity/limity-api.md"};function r(l,i,c,z,y,d){return o(),t("div",null,[...i[0]||(i[0]=[e(`<h2 id="limity-zadan-api" tabindex="-1">Limity żądań API <a class="header-anchor" href="#limity-zadan-api" aria-label="Permalink to &quot;Limity żądań API&quot;">​</a></h2><p>22.11.2025</p><p>Ze względu na skalę działania KSeF oraz jego publiczny charakter, wprowadzono mechanizmy ograniczające intensywność żądań API. Ich celem jest ochrona stabilności systemu, ochrona przed cyber zagrożeniami oraz zapewnienie równych warunków dostępu dla wszystkich użytkowników. Limity określają maksymalną liczbę zapytań, które można wykonać w określonym czasie i wymuszają taki sposób integracji, który jest zgodny z założeniami architektury systemu.</p><h3 id="ogolne-zasady-limitow" tabindex="-1">Ogólne zasady limitów <a class="header-anchor" href="#ogolne-zasady-limitow" aria-label="Permalink to &quot;Ogólne zasady limitów&quot;">​</a></h3><h4 id="_1-sposob-naliczania-limitow" tabindex="-1">1. Sposób naliczania limitów <a class="header-anchor" href="#_1-sposob-naliczania-limitow" aria-label="Permalink to &quot;1. Sposób naliczania limitów&quot;">​</a></h4><p>Wszystkie żądania do API KSeF podlegają limitom. Ograniczenia te obejmują każde wywołanie chronionego endpointu. Dla potrzeb rozliczania ruchu żądania są grupowane według pary: kontekst i adres IP.</p><ul><li><strong>kontekst</strong> - określony przez <code>ContextIdentifier</code> (<code>Nip</code>, <code>InternalId</code> lub <code>NipVatUe</code>) przekazany przy uwierzytelnianiu.</li><li><strong>adres IP</strong> - adres IP z którego nawiązywane jest połączenie sieciowe.</li></ul><p>Limity żądań są naliczane niezależnie dla każdej pary: kontekst i adres IP. Oznacza to, że ruch w tym samym kontekście, ale z różnych adresów IP, rozliczany jest osobno.</p><p>Przykład<br> Biuro księgowe A pobiera faktury w imieniu firmy B, korzystając z kontekstu firmy B (NIP) i łącząc się z KSeF z adresu IP1. Równocześnie firma B pobiera faktury samodzielnie, w tym samym kontekście (swoim NIP-ie), ale z innego adresu IP - IP2. Mimo wspólnego kontekstu, różne adresy IP powodują, że limity są naliczane niezależnie. W takiej sytuacji system traktuje każde połączenie jako oddzielną parę (kontekst + adres IP) i nalicza limity niezależnie: osobno dla biura księgowego A i osobno dla firmy B.</p><p><strong>Jednostki limitów</strong><br> W tabelach limitów stosowane są następujące oznaczenia:</p><ul><li>req/s - liczba żądań na sekundę,</li><li>req/min - liczba żądań na minutę,</li><li>req/h - liczba żądań na godzinę.</li></ul><p><strong>Model naliczania limitów (przesuwające się okno czasowe - sliding/rolling window)</strong><br> Limity są egzekwowane w modelu przesuwającego się okna czasowego. W każdej chwili zliczane są żądania wykonane w okresie:</p><ul><li>dla progu req/h - w ostatnich 60 minutach,</li><li>dla progu req/min - w ostatnich 60 sekundach,</li><li>dla progu req/s - w ostatniej sekundzie.</li></ul><p>Okna nie są wyrównywane do pełnych godzin ani minut (nie &quot;zerują się&quot; o :00). Wszystkie progi (req/s, req/min, req/h) obowiązują równolegle - blokada jest wyzwalana przy pierwszym przekroczeniu któregokolwiek z nich.</p><h4 id="_2-po-przekroczeniu-limitu-system-blokuje-dostep-do-api" tabindex="-1">2. Po przekroczeniu limitu system blokuje dostęp do API <a class="header-anchor" href="#_2-po-przekroczeniu-limitu-system-blokuje-dostep-do-api" aria-label="Permalink to &quot;2. Po przekroczeniu limitu system blokuje dostęp do API&quot;">​</a></h4><p>W przypadku przekroczenia limitów żądań API zwracany jest kod HTTP <strong>429 Too Many Requests</strong>, a kolejne żądania są tymczasowo blokowane.<br> Okres trwania blokady jest <strong>dynamiczny</strong> i zależy od częstotliwości oraz skali przekroczeń. Dokładny czas blokady jest zwracany w nagłówku odpowiedzi <code>Retry-After</code> (w sekundach). Wielokrotne przekroczenia mogą skutkować znacznym wydłużeniem blokady.</p><p>Przykład odpowiedzi 429:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HTTP/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 429</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Too Many Requests</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Content-Type: application/json</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Retry-After: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">429</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Too Many Requests&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Przekroczono limit 20 żądań na minutę. Spróbuj ponownie po 30 sekundach.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="_3-rejestrowanie-przekroczen" tabindex="-1">3. Rejestrowanie przekroczeń <a class="header-anchor" href="#_3-rejestrowanie-przekroczen" aria-label="Permalink to &quot;3. Rejestrowanie przekroczeń&quot;">​</a></h4><p>Wszystkie przypadki przekroczenia limitów żądań są rejestrowane i analizowane przez mechanizmy bezpieczeństwa. Dane te służą do monitorowania stabilności API oraz wykrywania potencjalnych nadużyć. Szczególną uwagę system zwraca na wzorce wskazujące na próby obchodzenia limitów, np. poprzez równoległe i systemowe używanie wielu adresów IP w ramach jednego kontekstu. Takie działania mogą zostać uznane za zagrożenie bezpieczeństwa.</p><p>W przypadku powtarzających się naruszeń lub skrajnego obciążenia system może automatycznie zastosować działania ochronne, takie jak:</p><ul><li>blokada dostępu do API KSeF dla danego podmiotu lub zakresu adresów IP,</li><li>ograniczenie dostępności dla najbardziej obciążających kontekstów.</li></ul><h4 id="_4-wyzsze-limity-w-godzinach-nocnych" tabindex="-1">4. Wyższe limity w godzinach nocnych <a class="header-anchor" href="#_4-wyzsze-limity-w-godzinach-nocnych" aria-label="Permalink to &quot;4. Wyższe limity w godzinach nocnych&quot;">​</a></h4><p>W godzinach 20:00-06:00 obowiązują wyższe limity pobierania niż w ciągu dnia. Szczegółowe wartości zostaną określone w początkowym okresie działania KSeF 2.0, po dostrojeniu parametrów do rzeczywistych obciążeń.</p><h4 id="_5-wstepne-załozenia-limitow" tabindex="-1">5. Wstępne założenia limitów <a class="header-anchor" href="#_5-wstepne-załozenia-limitow" aria-label="Permalink to &quot;5. Wstępne założenia limitów&quot;">​</a></h4><p>Limity żądań API zostały określone na podstawie przewidywanych scenariuszy wykorzystania systemu i modeli obciążeń.</p><p>Rzeczywisty charakter ruchu będzie zależeć od sposobu implementacji integracji w systemach zewnętrznych oraz od generowanych przez nie wzorców obciążenia. Oznacza to, że limity ustalone na etapie projektowym mogą różnić się od wartości utrzymywanych w środowisku produkcyjnym.</p><p>Z tego względu limity mają charakter dynamiczny i mogą być dostosowywane w zależności od warunków eksploatacyjnych oraz zachowania integratorów. W szczególności dopuszcza się ich czasowe obniżenie w przypadku intensywnego lub nieefektywnego korzystania z API.</p><h3 id="limity-na-srodowiskach" tabindex="-1">Limity na środowiskach <a class="header-anchor" href="#limity-na-srodowiskach" aria-label="Permalink to &quot;Limity na środowiskach&quot;">​</a></h3><p><strong>Środowisko TE (testowe)</strong> Na środowisku TE limity zostały skonfigurowane tak, aby umożliwić swobodną pracę integratorów i testowanie integracji bez ryzyka blokad. Domyślne wartości limitów są <strong>dziesięciokrotnie wyższe</strong> niż na produkcji, co pozwala na intensywne testy. Dodatkowo, dzięki udostępnionym endpointom można symulować różne scenariusze:</p><ul><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits~1production/post" target="_blank" rel="noreferrer">POST /testdata/rate-limits/production</a> - aktywuje limity takie jak na produkcji (PRD),</li><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits/post" target="_blank" rel="noreferrer">POST /testdata/rate-limits</a> - pozwala ustawić własne wartości,</li><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits/delete" target="_blank" rel="noreferrer">DELETE /testdata/rate-limits</a> - przywraca domyślne limity środowiska TE.</li></ul><p><strong>Środowisko DEMO (preprodukcyjne)</strong> Na środowisku DEMO obowiązują <strong>takie same limity jak na produkcji</strong> dla danego kontekstu. Wartości te są <strong>replikowane z PRD</strong> i służą do końcowej walidacji wydajności oraz stabilności integracji przed wdrożeniem produkcyjnym.</p><p><strong>Środowisko PRD (produkcyjne)</strong> Na środowisku PRD stosowane są <strong>domyślne limity</strong> określone w niniejszej dokumentacji. W przypadkach uzasadnionych - np. dużej skali przetwarzania faktur - przewidziana jest możliwość <strong>złożenia wniosku o podniesienie limitów</strong> za pośrednictwem dedykowanego formularza (w przygotowaniu).</p><h2 id="pobieranie-faktur-limity" tabindex="-1">Pobieranie faktur - limity <a class="header-anchor" href="#pobieranie-faktur-limity" aria-label="Permalink to &quot;Pobieranie faktur - limity&quot;">​</a></h2><h3 id="załozenia-architektoniczne" tabindex="-1">Założenia architektoniczne <a class="header-anchor" href="#załozenia-architektoniczne" aria-label="Permalink to &quot;Założenia architektoniczne&quot;">​</a></h3><p>API KSeF w obszarze pobierania faktur zostało zaprojektowane jako mechanizm <strong>synchronizacji dokumentów</strong> pomiędzy centralnym repozytorium a lokalną bazą danych systemów zewnętrznych. Kluczowym założeniem jest, aby operacje biznesowe, takie jak wyszukiwanie, filtrowanie czy raportowanie, były wykonywane na danych przechowywanych lokalnie, które zostały wcześniej zsynchronizowane z KSeF. Takie podejście zwiększa stabilność działania, minimalizuje ryzyko przeciążenia systemu i pozwala na bardziej elastyczne wykorzystanie danych przez aplikacje klienckie.</p><p>API KSeF w zakresie pobierania faktur nie jest przeznaczone do obsługi bezpośrednich operacji użytkowników końcowych w czasie rzeczywistym. Oznacza to, że nie powinno być wykorzystywane do:</p><ul><li>pobierania pojedynczych faktur na żądanie użytkownika, np. podgląd faktury,</li><li>pobierania listy metadanych faktur lub inicjowania eksportu paczek w reakcji na bieżące akcje w aplikacji, z wyjątkiem sytuacji, gdy użytkownik świadomie uruchamia synchronizację danych.</li></ul><h3 id="rekomendowany-sposob-integracji-w-zakresie-pobierania" tabindex="-1">Rekomendowany sposób integracji w zakresie pobierania <a class="header-anchor" href="#rekomendowany-sposob-integracji-w-zakresie-pobierania" aria-label="Permalink to &quot;Rekomendowany sposób integracji w zakresie pobierania&quot;">​</a></h3><p>Do synchronizacji przyrostowej wykorzystywany jest endpoint <code>/invoices/query/metadata</code>. Szczegółowe zasady synchronizacji przyrostowej opisano w osobnym dokumencie.</p><p>W zależności od wolumenu faktur można stosować różne podejścia do ich pobierania:</p><ol><li><strong>Scenariusze niskiego wolumenu</strong> - jeżeli liczba faktur jest ograniczona i możliwa do obsłużenia w ramach dostępnych limitów w oczekiwanym czasie, można pobierać je synchronicznie wywołując <code>/invoices/ksef/{ksefNumber}</code> dla wybranych dokumentów.</li><li><strong>Scenariusze wysokiego wolumenu</strong> - jeżeli liczba dokumentów jest znacząca i obsługa w trybie synchronicznym staje się niepraktyczna, zaleca się użycie mechanizmu eksportu (<code>/invoices/exports</code>). Eksport działa asynchronicznie, jest kolejkowany i dzięki temu nie wpływa negatywnie na wydajność systemu.</li><li><strong>Operacje biznesowe</strong> - niezależnie od wybranej strategii, wszystkie działania użytkowników (wyszukiwanie, filtrowanie, raportowanie) powinny być realizowane na <strong>lokalnej bazie danych</strong>, zsynchronizowanej wcześniej z KSeF.</li></ol><h3 id="tryby-synchronizacji-i-pobierania-faktur" tabindex="-1">Tryby synchronizacji i pobierania faktur <a class="header-anchor" href="#tryby-synchronizacji-i-pobierania-faktur" aria-label="Permalink to &quot;Tryby synchronizacji i pobierania faktur&quot;">​</a></h3><p>Pobranie faktury do systemu księgowego może być realizowane w trzech trybach:</p><ol><li><strong>Na żądanie użytkownika</strong> - synchronizacja przyrostowa uruchamiana jest <strong>manualnie</strong> przez użytkownika, od ostatniego potwierdzonego punktu kontrolnego.</li><li><strong>Cyklicznie</strong> - synchronizacja przyrostowa wykonywana jest automatycznie zgodnie z harmonogramem systemu.</li><li><strong>Tryb mieszany</strong> - synchronizacja przyrostowa działa cyklicznie, a dodatkowo użytkownik może ją uruchomić manualnie na żądanie.</li></ol><h3 id="czestotliwosc-odpytywania" tabindex="-1">Częstotliwość odpytywania <a class="header-anchor" href="#czestotliwosc-odpytywania" aria-label="Permalink to &quot;Częstotliwość odpytywania&quot;">​</a></h3><ul><li><strong>Nie zaleca się harmonogramów o wysokiej częstotliwości</strong>. W środowisku produkcyjnym interwał cykliczny nie powinien być krótszy niż 15 minut dla każdego podmiotu występującego na fakturze (Podmiot 1, Podmiot 2, Podmiot 3, Podmiot upoważniony).</li><li><strong>Profile niskiego wolumenu.</strong> Zaleca się pobieranie na żądanie, uzupełnione cyklem np. raz na dobę w oknie nocnym.</li><li><strong>Data otrzymania faktury.</strong> Datą otrzymania faktury jest data nadania numeru KSeF. Numer ten jest przypisywany automatycznie przez system w chwili przetworzenia faktury i nie zależy od momentu jej pobrania do systemu księgowego.</li></ul><h3 id="przykłady-niezalecanej-implementacji" tabindex="-1">Przykłady niezalecanej implementacji <a class="header-anchor" href="#przykłady-niezalecanej-implementacji" aria-label="Permalink to &quot;Przykłady niezalecanej implementacji&quot;">​</a></h3><p>Niewłaściwa integracja może prowadzić do blokady w API. Do najczęstszych błędów należą:</p><ol><li>Synchronizacja wyłącznie poprzez pobieranie pojedynczych faktur (ścieżka synchroniczna), bez wykorzystania eksportu paczek faktur. Takie podejście jest dopuszczalne jedynie w profilach o niskim wolumenie; przy większej liczbie dokumentów należy korzystać z mechanizmu <code>/invoices/exports</code>.</li><li>Obsługa żądań użytkowników końcowych (np. wyświetlanie pełnej treści faktury w aplikacji, pobieranie pliku XML) poprzez bezpośrednie wywołania API KSeF zamiast korzystania z lokalnej bazy.</li></ol><h3 id="szczegołowe-limity" tabindex="-1">Szczegółowe limity <a class="header-anchor" href="#szczegołowe-limity" aria-label="Permalink to &quot;Szczegółowe limity&quot;">​</a></h3>`,51),a("table",{tabindex:"0"},[a("thead",null,[a("tr",null,[a("th",null,"Endpoint"),a("th"),a("th",null,"req/s"),a("th",null,"req/min"),a("th",null,"req/h")])]),a("tbody",null,[a("tr",null,[a("td",null,"Pobranie listy metadanych faktur"),a("td",null,"POST /invoices/query/metadata"),a("td",null,"8"),a("td",null,"16"),a("td",null,"20")]),a("tr",null,[a("td",null,"Eksport paczki faktur"),a("td",null,"POST /invoices/exports"),a("td",null,"4"),a("td",null,"8"),a("td",null,"20")]),a("tr",null,[a("td",null,"Pobranie statusu eksportu paczki faktur"),a("td",{referenceNumber:""},"/invoices/exports/"),a("td",null,"10"),a("td",null,"60"),a("td",null,"600")]),a("tr",null,[a("td",null,"Pobranie faktury po numerze KSeF"),a("td",{ksefNumber:""},"GET /invoices/ksef/"),a("td",null,"8"),a("td",null,"16"),a("td",null,"64")])])],-1),e('<p><strong>Uwaga:</strong> Jeżeli w scenariuszach biznesowych organizacji dostępne limity pobierania faktur są niewystarczające, prosimy o kontakt z działem wsparcia KSeF w celu indywidualnej analizy i dobrania odpowiedniego rozwiązania.</p><h2 id="wysyłka-faktur-limity" tabindex="-1">Wysyłka faktur - limity <a class="header-anchor" href="#wysyłka-faktur-limity" aria-label="Permalink to &quot;Wysyłka faktur - limity&quot;">​</a></h2><h3 id="załozenia-architektoniczne-1" tabindex="-1">Założenia architektoniczne <a class="header-anchor" href="#załozenia-architektoniczne-1" aria-label="Permalink to &quot;Założenia architektoniczne&quot;">​</a></h3><ul><li>Wysyłka faktur bez względu na typ wysyłki jest kolejkowana.</li><li>Przetwarzanie jest zoptymalizowane pod jak najszybsze potwierdzenie poprawności faktury i zwrócenie numeru KSeF.</li></ul><h4 id="wysyłka-wsadowa-paczki-faktur" tabindex="-1">Wysyłka wsadowa (paczki faktur): <a class="header-anchor" href="#wysyłka-wsadowa-paczki-faktur" aria-label="Permalink to &quot;Wysyłka wsadowa (paczki faktur):&quot;">​</a></h4><ul><li>Paczka faktur jest traktowana jako jedna wiadomość w kolejce (referencja do paczki zamiast osobnych wpisów dla każdej faktury) i przetwarzana z takim samym priorytetem jak pojedynczy dokument.</li><li>Wysyłka w paczce ogranicza narzut sieciowy i operacyjny, ponieważ: <ul><li>wykonywana jest mniejsza liczba żądań HTTP,</li><li>operacje na zawartości (odszyfrowanie, walidacja, zapis) wykonywane są batchowo, co stanowi najwydajniejszy sposób obsługi wielu dokumentów jednocześnie.</li></ul></li><li>Kompresja wsadu. Ze względu na format XML i wysoką powtarzalność elementów między fakturami (stała struktura, podobne nazwy pól, powtarzalne bloki) osiągany współczynnik kompresji jest zwykle bardzo korzystny, co znacząco zmniejsza wolumen danych i skraca czas transmisji. W praktyce szybciej jest przesłać jedną paczkę zawierającą np. 100 faktur niż 100 pojedynczych faktur w sesji interaktywnej.</li><li>Limity. Mechanizm limitów działa niezależnie od trybu wysyłki. Wysyłka wsadowa z natury zmniejsza liczbę żądań i ułatwia efektywne wykorzystanie dostępnych limitów.</li><li>Zastosowanie. Tryb wsadowy zalecany jest wszędzie tam, gdzie w jednym oknie operacyjnym przekazywanych jest więcej niż jeden dokument. W szczególności sprawdza się przy rozliczeniach cyklicznych klientów, w e-commerce oraz w zautomatyzowanych procesach fakturowania.</li></ul><p>Przykładowe scenariusze zastosowania trybu wsadowego:</p><ul><li><strong>Sklep internetowy (e-commerce).</strong> Zamówienia i płatności są przetwarzane asynchronicznie, a faktury wystawiane automatycznie przez system ERP lub moduł fakturowania. Pojedyncza faktura nie musi być przesyłane do KSeF natychmiast po wystawieniu. Wydzielony proces może agregować wystawione faktury i cyklicznie - np. co 5 minut - przesyłać je w paczkach wsadowych do KSeF, co znacząco ogranicza liczbę żądań HTTP i optymalizuje wykorzystanie limitów.</li><li><strong>Usługi subskrypcyjne / rozliczenia cykliczne.</strong> Faktury są generowane zbiorczo raz dziennie lub raz w miesiącu (np. w telekomunikacji lub mediach) i przesyłane w jednej paczce w ramach zaplanowanej sesji wsadowej.</li><li><strong>Zautomatyzowane procesy fakturowania w przedsiębiorstwach.</strong> Występują np. w sektorze dystrybucji, logistyki, produkcji lub usług zlecanych w modelu B2B. Faktury generowane są automatycznie na podstawie zdarzeń systemowych (dostawy, realizacje zleceń) i przesyłane zbiorczo, np. po zakończeniu operacji.</li></ul><p><strong>Zalecenie:</strong> dla zapewnienia maksymalnej efektywności integracji, zaleca się agregowanie dokumentów w jednej sesji wsadowej wszędzie tam, gdzie jest to możliwe z punktu widzenia procesów biznesowych. Pozwala to ograniczyć liczbę żądań API oraz optymalizuje wykorzystanie dostępnych limitów.</p><p><strong>Szczegółowe limity</strong></p><table tabindex="0"><thead><tr><th>Endpoint</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Otwarcie sesji wsadowej *</td><td>POST /sessions/batch</td><td>10</td><td>20</td><td>60</td></tr><tr><td>Zamknięcie sesji wsadowej</td><td>POST /sessions/batch/{referenceNumber}/close</td><td>10</td><td>20</td><td>60</td></tr></tbody></table><p><strong>Wysyłka części paczki</strong> - żądania przesyłające części paczki w ramach jednej sesji wsadowej nie są objęte limitami API. W przypadku paczek podzielonych na wiele części zaleca się ich równoległe (wielowątkowe) przesyłanie, co znacząco skraca czas wysyłki.</p><h4 id="wysyłka-interaktywna-pojedynczo" tabindex="-1">Wysyłka interaktywna (pojedynczo) <a class="header-anchor" href="#wysyłka-interaktywna-pojedynczo" aria-label="Permalink to &quot;Wysyłka interaktywna (pojedynczo)&quot;">​</a></h4><p>Tryb interaktywny został zaprojektowany z myślą o scenariuszach wymagających szybkiej rejestracji pojedynczych faktur i natychmiastowego uzyskania numeru KSeF. W odróżnieniu od sesji wsadowej, każda faktura przesyłana jest niezależnie w ramach aktywnej sesji interaktywnej. Jego celem jest maksymalne skrócenie czasu potrzebnego na uzyskanie numeru KSeF dla pojedynczego dokumentu. Zastosowanie obejmuje scenariusze o niskim wolumenie, w których przesyłane są pojedyncze faktury.</p><p>Przykładowe scenariusze zastosowania trybu interaktywnego:</p><ul><li><strong>Punkt sprzedaży detalicznej (POS)</strong>. Po zakończeniu transakcji wystawiana jest faktura, a system rejestruje ją natychmiast w KSeF i zwraca numer KSeF celem wydruku lub prezentacji klientowi.</li><li><strong>Aplikacje mobilne i lekkie systemy sprzedażowe</strong> nie posiadające mechanizmu kolejkowania lub buforowania, wysyłające faktury od razu po ich wystawieniu.</li><li><strong>Zdarzenia jednostkowe lub nieregularne</strong> np. pojedyncza faktura korygująca.</li></ul><p>Tryb interaktywny, mimo większego narzutu sieciowego w przypadku większych wolumenów, jest niezbędnym uzupełnieniem trybu wsadowego w scenariuszach wymagających bieżącej reakcji lub natychmiastowej rejestracji dokumentu w KSeF. Należy go stosować wyłącznie tam, gdzie natychmiastowe przetworzenie faktury jest kluczowe dla procesu biznesowego lub gdy skala operacji nie uzasadnia wykorzystania sesji wsadowej.</p><p><strong>Szczegółowe limity</strong></p><table tabindex="0"><thead><tr><th>Endpoint</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Otwarcie sesji interaktywnej</td><td>POST /sessions/online</td><td>10</td><td>30</td><td>120</td></tr><tr><td>Wysłanie faktury *</td><td>POST /sessions/online/{referenceNumber}/invoices</td><td>10</td><td>30</td><td>180</td></tr><tr><td>Zamknięcie sesji interaktywnej</td><td>POST /sessions/online/{referenceNumber}/close</td><td>10</td><td>30</td><td>120</td></tr></tbody></table><p>* <strong>Uwaga:</strong> Jeżeli w scenariuszach biznesowych organizacji regularnie osiągane są limity wysyłki w sesji interaktywnej, w pierwszej kolejności należy rozważyć zastosowanie trybu wsadowego, który pozwala efektywniej wykorzystać dostępne zasoby i limity. W sytuacjach, gdy użycie sesji interaktywnej jest niezbędne, a osiągane limity pozostają niewystarczające, prosimy o kontakt z działem wsparcia KSeF w celu indywidualnej analizy i pomocy w doborze rozwiązania.</p><h3 id="status-sesji-i-faktur" tabindex="-1">Status sesji i faktur <a class="header-anchor" href="#status-sesji-i-faktur" aria-label="Permalink to &quot;Status sesji i faktur&quot;">​</a></h3><p><strong>Szczegółowe limity</strong></p>',22),a("table",{tabindex:"0"},[a("thead",null,[a("tr",null,[a("th",null,"Endpoint"),a("th"),a("th",null,"req/s"),a("th",null,"req/min"),a("th",null,"req/h")])]),a("tbody",null,[a("tr",null,[a("td",null,"Pobranie statusu faktury z sesji"),a("td",{invoiceReferenceNumber:""},"GET /sessions/{referenceNumber}/invoices/"),a("td",null,"30"),a("td",null,"120"),a("td",null,"1200")]),a("tr",null,[a("td",null,"Pobranie listy sesji"),a("td",null,"GET /sessions"),a("td",null,"5"),a("td",null,"10"),a("td",null,"60")]),a("tr",null,[a("td",null,"Pobranie faktur sesji"),a("td",null,"GET /sessions/{referenceNumber}/invoices"),a("td",null,"10"),a("td",null,"20"),a("td",null,"200")]),a("tr",null,[a("td",null,"Pobranie niepoprawnie przetworzonych faktur sesji"),a("td",null,"GET /sessions/{referenceNumber}/invoices/failed"),a("td",null,"10"),a("td",null,"20"),a("td",null,"200")]),a("tr",null,[a("td",null,"Pozostałe"),a("td",null,"GET /sessions/*"),a("td",null,"10"),a("td",null,"120"),a("td",null,"1200")])])],-1),e('<h2 id="pozostałe" tabindex="-1">Pozostałe <a class="header-anchor" href="#pozostałe" aria-label="Permalink to &quot;Pozostałe&quot;">​</a></h2><p>Domyślne limity obowiązują dla wszystkich zasobów API, które nie mają określonych wartości szczegółowych w niniejszej dokumentacji. Każdy taki endpoint posiada własny licznik limitów, a jego żądania nie wpływają na inne zasoby.</p><p>Limity te dotyczą wyłącznie zasobów chronionych. Nie obejmują one publicznych zasobów API, takich jak <code>/auth/challenge</code>, które nie wymagają uwierzytelnienia i posiadają własne mechanizmy ochrony - limit wynosi 60 żądań na sekundę dla jednego adresu IP.</p><table tabindex="0"><thead><tr><th>Endpoint</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Pozostałe</td><td>POST/GET /*</td><td>10</td><td>30</td><td>120</td></tr></tbody></table><p>Powiązane dokumenty:</p><ul><li><a href="./limity.html">Limity</a></li></ul>',6)])])}const p=n(s,[["render",r]]);export{k as __pageData,p as default};
